mapper.select:
SELECT v.vehicle_id, v.license_plate, v.line_id, v.model, v.purchase_time, v.status, l.line_name FROM vehicle v LEFT JOIN line l ON v.line_id = l.line_id
AND (v.license_plate LIKE CONCAT('%', #{keyword}, '%') OR v.model LIKE CONCAT('%', #{keyword}, '%'))
AND v.line_id = #{lineId}
AND v.status = #{status}
ORDER BY v.purchase_time DESC

mapper.update:
UPDATE vehicle
license_plate = #{licensePlate}, line_id = #{lineId}, model = #{model}, purchase_time = #{purchaseTime}, status = #{status},
WHERE vehicle_id = #{vehicleId}
